import http from "node:http";
import { afterAll, afterEach, beforeAll, beforeEach, describe, expect, it, vi, } from "vitest";
import * as config from "../config.js";
import { runTrackSkill } from "./trackSkill.js";
vi.mock("../config.js", async (importOriginal) => {
    const actual = (await importOriginal());
    return {
        ...actual,
        getConfig: vi.fn(actual.getConfig),
    };
});
const testPlatform = {
    authPath: "test",
    loginHint: "/test:login",
    setupHint: "/test:setup",
    updateHint: "/test:update",
    repo: "Test/test-plugin",
    cliBinary: "test",
    displayName: "Test Client",
    supportsAutoUpdate: false,
    marketplaceName: "test",
    pluginName: "test",
    marketplacePreRegistered: false,
};
describe("runTrackSkill", () => {
    const originalEnv = { ...process.env };
    let server;
    let baseUrl;
    let requestLog = [];
    let handler = (_req, res) => {
        res.writeHead(200, { "Content-Type": "application/json" });
        res.end(JSON.stringify({ status: "ok" }));
    };
    beforeAll(async () => {
        server = http.createServer((req, res) => {
            let body = "";
            req.on("data", (chunk) => {
                body += chunk;
            });
            req.on("end", () => {
                requestLog.push({
                    method: req.method ?? "",
                    url: req.url ?? "",
                    headers: req.headers,
                    body,
                });
                handler(req, res);
            });
        });
        await new Promise((resolve) => {
            server.listen(0, "127.0.0.1", resolve);
        });
        const addr = server.address();
        baseUrl = `http://127.0.0.1:${addr.port}`;
    });
    afterAll(async () => {
        await new Promise((resolve, reject) => {
            server.close((err) => (err ? reject(err) : resolve()));
        });
    });
    beforeEach(() => {
        requestLog = [];
        process.env.BITFAB_SERVICE_URL = baseUrl;
        process.env.BITFAB_API_KEY = "test-api-key";
    });
    afterEach(() => {
        process.env = { ...originalEnv };
        handler = (_req, res) => {
            res.writeHead(200, { "Content-Type": "application/json" });
            res.end(JSON.stringify({ status: "ok" }));
        };
    });
    it("POSTs to /api/plugin/analytics/skill with skill name and client headers", async () => {
        await runTrackSkill("setup", "9.9.9", testPlatform);
        expect(requestLog).toHaveLength(1);
        const req = requestLog[0];
        expect(req.method).toBe("POST");
        expect(req.url).toBe("/api/plugin/analytics/skill");
        expect(req.headers.authorization).toBe("Bearer test-api-key");
        expect(req.headers["x-bitfab-client-name"]).toBe("test");
        expect(req.headers["x-bitfab-client-display-name"]).toBe("Test Client");
        expect(req.headers["x-bitfab-client-version"]).toBe("9.9.9");
        expect(req.headers["x-bitfab-install-id"]).toBeDefined();
        expect(JSON.parse(req.body)).toEqual({ skillName: "setup" });
    });
    it("is a no-op when no API key is configured", async () => {
        vi.mocked(config.getConfig).mockReturnValueOnce({
            serviceUrl: baseUrl,
            apiKey: null,
            verbose: false,
            debug: false,
        });
        await runTrackSkill("setup", "9.9.9", testPlatform);
        expect(requestLog).toHaveLength(0);
    });
    it("swallows network errors without throwing", async () => {
        process.env.BITFAB_SERVICE_URL = "http://127.0.0.1:1";
        await expect(runTrackSkill("setup", "9.9.9", testPlatform)).resolves.toBeUndefined();
    });
    it("swallows non-2xx responses without throwing", async () => {
        handler = (_req, res) => {
            res.writeHead(500, { "Content-Type": "application/json" });
            res.end(JSON.stringify({ error: "boom" }));
        };
        await expect(runTrackSkill("setup", "9.9.9", testPlatform)).resolves.toBeUndefined();
    });
});
